import React, { useState } from "react";
import { api } from "../../api";
import "../RegisterPage.css"; // Используем те же стили

const LoginPage = ({ onSuccess, onNavigate }) => {
  // 1. Стейты должны быть ПЕРВЫМИ внутри функции
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  // 2. Функция handleSubmit должна быть ВНУТРИ LoginPage
  const handleSubmit = async (e) => {
    e.preventDefault();
    console.log("Попытка входа...", email); // Для отладки
    
    try {
      const data = await api.login({ email, password });
      if (data && data.accessToken) {
        onSuccess(data.accessToken, data.user);
      }
    } catch (err) {
      console.error("Ошибка при входе:", err);
      alert(err.response?.data?.error || "Ошибка соединения с сервером");
    }
  };

  // 3. Возвращаем JSX
  return (
    <div style={{ padding: "20px", maxWidth: "400px", margin: "0 auto" }}>
      <h2>Вход</h2>
      <form onSubmit={handleSubmit}> 
        <div style={{ marginBottom: "10px" }}>
          <input
            type="email"
            placeholder="Email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            style={{ width: "100%", padding: "8px" }}
            required
          />
        </div>
        <div style={{ marginBottom: "10px" }}>
          <input
            type="password"
            placeholder="Пароль"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            style={{ width: "100%", padding: "8px" }}
            required
          />
        </div>
        <button type="submit" style={{ width: "100%", padding: "10px", cursor: "pointer" }}>
          Войти
        </button>
      </form>
      <button 
        onClick={onNavigate} 
        style={{ marginTop: "10px", background: "none", border: "none", color: "blue", cursor: "pointer" }}
      >
        Нет аккаунта? Зарегистрироваться
      </button>
    </div>
  );
};

export default LoginPage;
